"use client"

import { matchaSpots } from "@/lib/matcha-spots"

interface GlobalLeaderboardProps {
  selectedSpot: number | null
  onSpotClick: (spotRank: number) => void
}

export function GlobalLeaderboard({ selectedSpot, onSpotClick }: GlobalLeaderboardProps) {
  return (
    <div className="flex flex-col h-full">
      {/* Leaderboard List */}
      <div className="flex-1 overflow-y-auto">
        <div className="space-y-2 p-3">
          {matchaSpots.map((spot) => {
            const isSelected = selectedSpot === spot.rank
            return (
              <button
                key={spot.rank}
                onClick={() => onSpotClick(spot.rank)}
                className={`w-full text-left p-3 rounded-lg transition-all duration-200 ${
                  isSelected
                    ? "bg-primary/20 border border-primary"
                    : "bg-accent/30 border border-border hover:bg-accent/50"
                }`}
              >
                <div className="flex items-start gap-3">
                  <div className="flex-shrink-0">
                    <div className="flex h-8 w-8 items-center justify-center rounded-full bg-primary/30 text-xs font-bold text-primary">
                      {spot.rank}
                    </div>
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-foreground text-sm truncate">
                      {spot.name}
                    </p>
                    <p className="text-xs text-muted-foreground truncate">
                      {spot.location}
                    </p>
                    <div className="flex items-center gap-2 mt-1">
                      <span className="text-xs font-medium text-muted-foreground">
                        {spot.rating} ★
                      </span>
                      <span className="text-xs text-muted-foreground italic">
                        {spot.vibe}
                      </span>
                    </div>
                  </div>
                </div>
              </button>
            )
          })}
        </div>
      </div>
    </div>
  )
}
